// src/services/worker/PaginationHelper.ts
init_logger();
var PaginationHelper = class {
  dbManager;
  constructor(dbManager) {
    this.dbManager = dbManager;
  }
  /**
   * Strip project path from file paths using heuristic
   * Converts "/Users/user/project/src/file.ts" -> "src/file.ts"
   * Uses first occurrence of project name from left (project root)
   */
  stripProjectPath(filePath, projectName) {
    const marker = `/${projectName}/`;
    const index = filePath.indexOf(marker);
    if (index !== -1) {
      return filePath.substring(index + marker.length);
    }
    return filePath;
  }
  /**
   * Strip project path from JSON array of file paths
   */
  stripProjectPaths(filePathsStr, projectName) {
    if (!filePathsStr) return filePathsStr;
    try {
      const paths = JSON.parse(filePathsStr);
      const strippedPaths = paths.map((p) => this.stripProjectPath(p, projectName));
      return JSON.stringify(strippedPaths);
    } catch (err) {
      logger.debug("WORKER", "File paths is plain string, using as-is", {}, err);
      return filePathsStr;
    }
  }
  /**
   * Sanitize observation by stripping project paths from files
   */
  sanitizeObservation(obs) {
    return {
      ...obs,
      files_read: this.stripProjectPaths(obs.files_read, obs.project),
      files_modified: this.stripProjectPaths(obs.files_modified, obs.project)
    };
  }
  /**
   * Get paginated observations
   */
  getObservations(offset, limit, project) {
    const result = this.paginate(
      "observations",
      "id, memory_session_id, project, type, title, subtitle, narrative, text, facts, concepts, files_read, files_modified, prompt_number, created_at, created_at_epoch",
      offset,
      limit,
      project
    );
    return {
      ...result,
      items: result.items.map((obs) => this.sanitizeObservation(obs))
    };
  }
  /**
   * Get paginated summaries
   */
  getSummaries(offset, limit, project) {
    const db = this.dbManager.getSessionStore().db;
    let query2 = `
      SELECT
        ss.id,
        s.content_session_id as session_id,
        ss.request,
        ss.investigated,
        ss.learned,
        ss.completed,
        ss.next_steps,
        ss.project,
        ss.created_at,
        ss.created_at_epoch
      FROM session_summaries ss
      JOIN sdk_sessions s ON ss.memory_session_id = s.memory_session_id
    `;
    const params = [];
    if (project) {
      query2 += " WHERE ss.project = ?";
      params.push(project);
    }
    query2 += " ORDER BY ss.created_at_epoch DESC LIMIT ? OFFSET ?";
    params.push(limit + 1, offset);
    const stmt = db.prepare(query2);
    const results = stmt.all(...params);
    return {
      items: results.slice(0, limit),
      hasMore: results.length > limit,
      offset,
      limit
    };
  }
  /**
   * Get paginated user prompts
   */
  getPrompts(offset, limit, project) {
    const db = this.dbManager.getSessionStore().db;
    let query2 = `
      SELECT up.id, up.content_session_id, s.project, up.prompt_number, up.prompt_text, up.created_at, up.created_at_epoch
      FROM user_prompts up
      JOIN sdk_sessions s ON up.content_session_id = s.content_session_id
    `;
    const params = [];
    if (project) {
      query2 += " WHERE s.project = ?";
      params.push(project);
    }
    query2 += " ORDER BY up.created_at_epoch DESC LIMIT ? OFFSET ?";
    params.push(limit + 1, offset);
    const stmt = db.prepare(query2);
    const results = stmt.all(...params);
    return {
      items: results.slice(0, limit),
      hasMore: results.length > limit,
      offset,
      limit
    };
  }
  /**
   * Generic pagination implementation (DRY)
   */
  paginate(table, columns, offset, limit, project) {
    const db = this.dbManager.getSessionStore().db;
    let query2 = `SELECT ${columns} FROM ${table}`;
    const params = [];
    if (project) {
      query2 += " WHERE project = ?";
      params.push(project);
    }
    query2 += " ORDER BY created_at_epoch DESC LIMIT ? OFFSET ?";
    params.push(limit + 1, offset);
    const stmt = db.prepare(query2);
    const results = stmt.all(...params);
    return {
      items: results.slice(0, limit),
      hasMore: results.length > limit,
      offset,
      limit
    };
  }
};

